properties.query:
// No native equivalent in Sentinel — UrlClickEvents.ActionType ==
// "ClickedThrough" is M365-Defender-only. If you have Defender for Office
// streaming into Sentinel, the equivalent table is `UrlClickEventsBeta`.
// Otherwise this UC has no Sentinel translation; surface via the SecurityAlert
// table when Defender raises an alert.
SecurityAlert
| where TimeGenerated > ago(30d)
| where ProviderName has "MDATP" or ProviderName has "Office365"
| where AlertName has "Safe Links" or AlertName has "ClickedThrough"
| project TimeGenerated, AlertName, AlertSeverity, CompromisedEntity, Description
| order by TimeGenerated desc
